                    } else if (ctl % 4 == 1) {
                        bw4.write("A");
                        bw4.flush();
                    } else if (ctl % 4 == 2) {
                        bw3.write("A");
                        bw3.flush();
                    } else if (ctl % 4 == 3) {
                        bw2.write("A");
                        bw2.flush();
                    }

                    outputThisRound[0] = true;
                    outputThisRound[1] = false;

                    System.out.println("outputA signal outputB!");
                    cond2.signal(); //唤醒B线程
                } catch (Exception e) {
                    e.printStackTrace();
                } finally {
                    lock.unlock();
                }

            }

            public void outputB() {

                lock.lock();

                try {
                    while (outputThisRound[1]) {
                        System.out.println("outputB begin to await!");
                        cond2.await();
                    }

                    if (ctl % 4 == 0) {
                        bw2.write("B");
                        bw2.flush();
                    } else if (ctl % 4 == 1) {
                        bw1.write("B");
                        bw1.flush();
                    } else if (ctl % 4 == 2) {
                        bw4.write("B");
                        bw4.flush();
                    } else if (ctl % 4 == 3) {
                        bw3.write("B");
                        bw3.flush();
                    }

                    outputThisRound[1] = true;
                    outputThisRound[2] = false;
                    System.out.println("outputB signal outputC!");
                    cond3.signal();
                } catch (Exception e) {
                    e.printStackTrace();
                } finally {
                    lock.unlock();
                }
            }

            public void outputC() {
                lock.lock();
                try {
                    while (outputThisRound[2]) {
                        System.out.println("outputC begin to await!");
                        cond3.await();
                    }

                    if (ctl % 4 == 0) {
                        bw3.write("C");
                        bw3.flush();
                    } else if (ctl % 4 == 1) {
                        bw2.write("C");
                        bw2.flush();
                    } else if (ctl % 4 == 2) {
                        bw1.write("C");
                        bw1.flush();
                    } else if (ctl % 4 == 3) {
                        bw4.write("C");
                        bw4.flush();
                    }

                    outputThisRound[2] = true;
                    outputThisRound[3] = false;
                    System.out.println("outputC signal outputD!");
                    cond4.signal();
                } catch (Exception e) {
                    e.printStackTrace();
                } finally {
                    lock.unlock();
                }
            }

            public void outputD() {
                lock.lock();

                try {
                    while (outputThisRound[3]) {
                        System.out.println("outputD begin to await!");
                        cond4.await();
                    }

                    if (ctl % 4 == 0) {
                        bw4.write("D");
                        bw4.flush();
                    } else if (ctl % 4 == 1) {
                        bw3.write("D");
                        bw3.flush();
                    } else if (ctl % 4 == 2) {
                        bw2.write("D");
                        bw2.flush();
                    } else if (ctl % 4 == 3) {
                        bw1.write("D");
                        bw1.flush();
                    }

                    outputThisRound[3] = true;
                    outputThisRound[0] = false;
                    ctl++;
                    System.out.println("outputD signal outputA!");
                    cond1.signal();
                } catch (Exception e) {
                    e.printStackTrace();
                } finally {
                    lock.unlock();
                }
            }
        }
    }

